// Dados do canal vindos do AI (item anterior no loop)
const chData = $('loop-by-channel-result').item.json;

// Resposta da YouTube Data API
const apiResponse = $input.first().json;
const items = apiResponse.items || [];
const yt = items[0] || null;

// Extrai métricas reais se o canal foi encontrado
let canal_id_real = chData.handle ? chData.handle.replace('@', '') : null;
let nome_canal_real = chData.channel_name;
let inscritos_real = 0;
let total_videos_real = 0;
let total_views_real = 0;
let canal_encontrado = false;

if (yt) {
  canal_encontrado = true;
  canal_id_real = yt.id || canal_id_real;
  nome_canal_real = yt.snippet?.title || nome_canal_real;
  inscritos_real = parseInt(yt.statistics?.subscriberCount || '0');
  total_videos_real = parseInt(yt.statistics?.videoCount || '0');
  total_views_real = parseInt(yt.statistics?.viewCount || '0');
}

// Fallback: se não encontrou pelo handle, mantém dados do AI
const parseSubs = (s) => {
  const str = String(s || '0').replace(/[,\s]/g, '').toLowerCase();
  if (str.includes('m')) return Math.round(parseFloat(str) * 1000000);
  if (str.includes('k')) return Math.round(parseFloat(str) * 1000);
  return parseInt(str) || 0;
};

const handle = chData.handle || '';
const canal_id = canal_id_real || (
  handle.startsWith('@')
    ? handle.slice(1)
    : String(chData.channel_name || 'canal')
        .replace(/[^a-zA-Z0-9_-]/g, '_')
        .toLowerCase()
);

const url_canal = handle.startsWith('@')
  ? `https://www.youtube.com/${handle}`
  : `https://www.youtube.com/@${canal_id}`;

return [{
  json: {
    ...chData,
    canal_id,
    nome_canal: nome_canal_real,
    url_canal,
    inscritos: canal_encontrado ? inscritos_real : parseSubs(chData.estimated_subs),
    total_videos: total_videos_real,
    total_views: total_views_real,
    views_medio_aproximado: total_videos_real > 0 ? Math.round(total_views_real / total_videos_real) : 0,
    canal_encontrado
  }
}];

const sd = $getWorkflowStaticData('global');
const novos24h = Number($json.novos_24h || 0);
const discoveryBatchSize = novos24h < 20 ? 30 : 20;

let kws = [];
let hints = [];
try { kws = JSON.parse($json.keywords || '[]'); } catch (e) { kws = []; }
try { hints = JSON.parse($json.search_hints || '[]'); } catch (e) { hints = []; }

const allKeywords = Array.from(new Set([
  ...(Array.isArray(kws) ? kws : []),
  ...(Array.isArray(hints) ? hints : []),
])).filter(Boolean);

sd.currentNiche = {
  nicho_id: $json.nicho_id,
  nome: $json.nome,
  slug: $json.slug,
  keywords: allKeywords,
