  seed_channels: $json.seed_channels || 'sem seed',
  novos_24h: novos24h,
  discovery_batch_size: discoveryBatchSize,
};

return [{
  json: {
    ...sd.currentNiche,
    lang: ($json.idioma || 'pt-BR').split('-')[0],
    known_channels: $json.known_channels || 'nenhum canal',
    keywords: allKeywords,
  }
}];

