const aiRaw = $input.first().json.content;
const sd = $getWorkflowStaticData('global');
const nichoData = sd.currentNiche || {};
const batchSize = Number(nichoData.discovery_batch_size || 20);
let channels = [];

try {
  let text = '';
  if (typeof aiRaw === 'string') text = aiRaw;
  else if (typeof aiRaw.content === 'string') text = aiRaw.content;
  else if (typeof aiRaw.text === 'string') text = aiRaw.text;
  else if (typeof aiRaw.output === 'string') text = aiRaw.output;
  else text = JSON.stringify(aiRaw);

  text = text.replace(/```json\n?|```\n?/g, '').trim();
  const match = text.match(/\[[\s\S]*\]/);
  if (match) channels = JSON.parse(match[0]);
} catch (e) {
  channels = [];
}

if (!Array.isArray(channels) || channels.length === 0) return [];

const normalizeName = (s) => String(s || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]/g, '');

const normalizeHandle = (s) => String(s || '')
  .toLowerCase()
  .replace('@', '')
  .replace(/[^a-z0-9_]/g, '');

const seen = new Set();
const normalized = [];
for (const ch of channels) {
  const channel_name = String(ch.channel_name || '').trim();
  const handle = String(ch.handle || '').trim();
  if (!channel_name) continue;

  const handleKey = normalizeHandle(handle);
  const nameKey = normalizeName(channel_name);
  const dedupKey = handleKey ? `h:${handleKey}` : `n:${nameKey}`;

  if (seen.has(dedupKey)) continue;
  seen.add(dedupKey);

  normalized.push({
    json: {
      channel_name,
      handle,
      estimated_subs: String(ch.estimated_subs || '0'),
      content_style: String(ch.content_style || ''),
      reason: String(ch.reason || ''),
      nicho_nome: nichoData.nome || '',
      nicho_slug: nichoData.slug || ''
    }
  });
}

return normalized.slice(0, batchSize);

