const chData = $('extract-youtube-metrics').item.json;
const aiItem = $input.first().json;
const raw = aiItem.content ?? aiItem.text ?? aiItem.output ?? aiItem;

let evaluation = {};
try {
  let text = '';
  if (typeof raw === 'string') text = raw;
  else if (typeof raw?.content === 'string') text = raw.content;
  else if (typeof raw?.text === 'string') text = raw.text;
  else if (typeof raw?.output === 'string') text = raw.output;
  else text = JSON.stringify(raw);

  text = text.replace(/```(?:json)?\s*|```/g, '').trim();
  const firstChar = text[0];
  if (firstChar === '{' || firstChar === '[') {
    evaluation = JSON.parse(text);
  } else {
    const i = text.indexOf('{');
    const j = text.lastIndexOf('}');
    if (i !== -1 && j !== -1 && j > i) {
      evaluation = JSON.parse(text.slice(i, j + 1));
    }
  }
} catch (e) {
  evaluation = {};
}

if (!chData.canal_encontrado) return [];

const score = Number(evaluation.score ?? 0);
if (score < 0.60 || evaluation.recomendacao === 'ignorar') return [];

return [{
  json: {
    plataforma: 'youtube',
    canal_id: chData.canal_id,
    nome_canal: chData.nome_canal,
    url_canal: chData.url_canal,
    nicho_alvo: chData.nicho_slug,
    inscritos: chData.inscritos || 0,
    views_medio_aproximado: chData.views_medio_aproximado || 0,
    total_videos: chData.total_videos || 0,
    total_views: chData.total_views || 0,
    tom_de_voz: evaluation.tom_de_voz || 'informativo e engajante',
    score: Number(score.toFixed(2)),
    ativo: score >= 0.70,
    data_ultima_analise: new Date().toISOString()
  }
}];

const items = $input.all();

if (!items.length) {
  return [{ json: {} }];
}

// Se quiser considerar todos:
const lista = items.map(i => i.json);

// Se quiser apenas ativos:
// const lista = items.map(i => i.json).filter(i => i.ativo === true);

if (!lista.length) {
  return [{ json: {} }];
}

const randomIndex = Math.floor(Math.random() * lista.length);
const itemAleatorio = lista[randomIndex];

return [
  {
    json: itemAleatorio
  }
];

